 1	import React, { FC } from 'react';
 2	
 3	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
 4	import AddBootableVolumeModal from '@kubevirt-utils/components/AddBootableVolumeModal/AddBootableVolumeModal';
 5	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import useCanCreateBootableVolume from '@kubevirt-utils/resources/bootableresources/hooks/useCanCreateBootableVolume';
 8	import { Button, ButtonVariant } from '@patternfly/react-core';
 9	
10	import './AddBootableVolumeLink.scss';
11	
12	type AddBootableVolumeLinkProps = {
13	  hidePopover?: () => void;
14	  loadError: Error;
15	  text?: string;
16	};
17	
18	const AddBootableVolumeLink: FC<AddBootableVolumeLinkProps> = ({
19	  hidePopover,
20	  loadError,
21	  text,
22	}) => {
23	  const { t } = useKubevirtTranslation();
24	  const { createModal } = useModal();
25	  const { onSelectCreatedVolume, volumeListNamespace } = useInstanceTypeVMStore();
26	
27	  const { canCreateDS, canCreatePVC } = useCanCreateBootableVolume(volumeListNamespace);
28	  const canCreate = canCreateDS || canCreatePVC;
29	
30	  return (
31	    <Button
32	      onClick={() => {
33	        hidePopover?.();
34	        createModal((props) => (
35	          <AddBootableVolumeModal onCreateVolume={onSelectCreatedVolume} {...props} />
36	        ));
37	      }}
38	      className="add-bootable-volume-link__inline-text"
39	      data-test-id="add-volume-button-under-list"
40	      isDisabled={!!loadError || !canCreate}
41	      variant={ButtonVariant.link}
42	    >
43	      {text || t('Add volume')}
44	    </Button>
45	  );
46	};
47	
48	export default AddBootableVolumeLink;

